  "inlineSchema": "// GoalDesk AI — Prisma Schema\n// All models for the MVP: User, Goal, Task, CalendarBlock, FocusSession, Device, DeviceMessage, DeviceEvent\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n}\n\n// ─── User ────────────────────────────────────────────────────────────────────\n// For MVP, a single demo user is seeded on first run.\n// planningRangeStart/End are customizable via the Settings page.\nmodel User {\n  id                 Int             @id @default(autoincrement())\n  name               String\n  email              String          @unique\n  planningRangeStart String          @default(\"09:00\") // HH:mm 24h format\n  planningRangeEnd   String          @default(\"22:00\") // HH:mm 24h format\n  createdAt          DateTime        @default(now())\n  goals              Goal[]\n  tasks              Task[]\n  calendarBlocks     CalendarBlock[]\n  focusSessions      FocusSession[]\n  devices            Device[]\n}\n\n// ─── Goal ────────────────────────────────────────────────────────────────────\n// A long-term goal the user wants to achieve (e.g. \"Learn AI engineering\").\n// Tasks are generated from goals by the AI/mock planner.\nmodel Goal {\n  id                 Int      @id @default(autoincrement())\n  userId             Int\n  title              String\n  category           String // Learning, School, Career, Project, Wellness, Personal, Other\n  description        String?\n  deadline           DateTime\n  priority           String // Low, Medium, High\n  preferredTimeOfDay String // Morning, Afternoon, Evening, Night, Flexible\n  dailyMinutes       Int\n  status             String   @default(\"Active\") // Active, Paused, Completed, Archived\n  createdAt          DateTime @default(now())\n  updatedAt          DateTime @updatedAt\n  user               User     @relation(fields: [userId], references: [id])\n  tasks              Task[]\n}\n\n// ─── Task ────────────────────────────────────────────────────────────────────\n// A small daily task generated from a goal. Can be scheduled into a time slot.\nmodel Task {\n  id               Int            @id @default(autoincrement())\n  userId           Int\n  goalId           Int\n  title            String\n  description      String?\n  estimatedMinutes Int\n  scheduledStart   DateTime?\n  scheduledEnd     DateTime?\n  priority         String // Low, Medium, High\n  status           String         @default(\"Unscheduled\") // Unscheduled, Scheduled, InProgress, Completed, Skipped\n  isAiGenerated    Boolean        @default(false)\n  isUserMoved      Boolean        @default(false)\n  createdAt        DateTime       @default(now())\n  updatedAt        DateTime       @updatedAt\n  user             User           @relation(fields: [userId], references: [id])\n  goal             Goal           @relation(fields: [goalId], references: [id])\n  focusSessions    FocusSession[]\n}\n\n// ─── CalendarBlock ───────────────────────────────────────────────────────────\n// A fixed time block representing an obligation (class, work, sleep, etc.).\n// Hard blocks cannot be moved by the scheduler.\nmodel CalendarBlock {\n  id          Int      @id @default(autoincrement())\n  userId      Int\n  title       String\n  blockType   String // Class, Work, Meeting, Appointment, Sleep, Commute, Meal, Club, Other\n  startTime   DateTime\n  endTime     DateTime\n  recurrence  String   @default(\"None\") // None, Weekly\n  isHardBlock Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n  user        User     @relation(fields: [userId], references: [id])\n}\n\n// ─── FocusSession ────────────────────────────────────────────────────────────\n// A timed work session for a specific task.\nmodel FocusSession {\n  id             Int       @id @default(autoincrement())\n  userId         Int\n  taskId         Int\n  startedAt      DateTime  @default(now())\n  endedAt        DateTime?\n  plannedMinutes Int\n  actualMinutes  Int?\n  status         String    @default(\"Active\") // Active, Paused, Completed, Cancelled\n  createdAt      DateTime  @default(now())\n  user           User      @relation(fields: [userId], references: [id])\n  task           Task      @relation(fields: [taskId], references: [id])\n}\n\n// ─── Device ──────────────────────────────────────────────────────────────────\n// Represents a Particle Argon IoT device paired to a user.\nmodel Device {\n  id               Int             @id @default(autoincrement())\n  userId           Int\n  particleDeviceId String\n  name             String\n  status           String          @default(\"Offline\") // Online, Offline\n  lastSeen         DateTime?\n  createdAt        DateTime        @default(now())\n  user             User            @relation(fields: [userId], references: [id])\n  messages         DeviceMessage[]\n  events           DeviceEvent[]\n}\n\n// ─── DeviceMessage ───────────────────────────────────────────────────────────\n// A message sent to the device's 16x2 LCD display.\nmodel DeviceMessage {\n  id          Int       @id @default(autoincrement())\n  deviceId    Int\n  line1       String // Max 16 characters\n  line2       String // Max 16 characters\n  messageType String // task, focus, reminder, motivation, complete, test\n  status      String    @default(\"Pending\") // Pending, Sent, Failed\n  sentAt      DateTime?\n  createdAt   DateTime  @default(now())\n  device      Device    @relation(fields: [deviceId], references: [id])\n}\n\n// ─── DeviceEvent ─────────────────────────────────────────────────────────────\n// An event received from the device (e.g. button press).\nmodel DeviceEvent {\n  id         Int      @id @default(autoincrement())\n  deviceId   Int\n  eventType  String // button_press, status\n  payload    String? // JSON string\n  receivedAt DateTime @default(now())\n  device     Device   @relation(fields: [deviceId], references: [id])\n}\n",
